sys_script.script:
(function executeRule(current, previous) {
    // Validate Appointment Date is in the future
    var apptDate = current.getValue('appointment_date');
    if (apptDate) {
        var appointment = new GlideDateTime(apptDate);
        var now = new GlideDateTime();
        if (appointment.compareTo(now) <= 0) {
            gs.addErrorMessage('Appointment Date must be in the future.');
            current.setAbortAction(true);
            return;
        }
    }

    // Validate Blood Request is in Assigned state (state=2)
    var bloodRequestId = current.getValue('blood_request');
    if (bloodRequestId) {
        var br = new GlideRecord('x_1920732_lifeli_0_blood_request');
        if (br.get(bloodRequestId)) {
            if (br.getValue('state') != '2') {
                gs.addErrorMessage('The Blood Request must be in the Assigned state to schedule an appointment.');
                current.setAbortAction(true);
                return;
            }
        }
    }

    // Validate Donor eligibility
    var donorId = current.getValue('donor');
    if (donorId) {
        var donor = new GlideRecord('x_1920732_lifeli_0_donor_profile');
        if (donor.get(donorId)) {
            if (donor.getValue('eligibility_status') != 'eligible') {
                gs.addErrorMessage('The selected donor is not currently eligible for donation.');
                current.setAbortAction(true);
                return;
            }
        }
    }
})(current, previous);
